@page "/privacy"
@using Microsoft.AspNetCore.Http
@attribute [ExcludeFromInteractiveRouting]
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (hasConsent)
{
    <div class="alert alert-success" role="alert">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning" role="alert">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

<h2>Cookie Usage</h2>
<p>
    This site uses cookies to improve your experience. By continuing to use
    this site you agree to the use of cookies in accordance with this policy.
</p>

<h2>What Are Cookies</h2>
<p>
    Cookies are small text files stored on your device when you visit a website.
    They help the site remember your preferences and understand how you interact
    with the content.
</p>

<h2>How We Use Cookies</h2>
<ul>
    <li><strong>Essential cookies</strong> – required for the site to function correctly.</li>
    <li><strong>Analytics cookies</strong> – help us understand how visitors use the site.</li>
    <li><strong>Preference cookies</strong> – remember your settings and choices.</li>
</ul>

@code {
    private bool hasConsent;

    protected override void OnInitialized()
    {
        var context = HttpContextAccessor.HttpContext;
        if (context is not null)
        {
            hasConsent = context.Request.Cookies.ContainsKey("consent");
        }
    }
}

